<template>
    <div>
        <div class="accordion" id="accordionExample">
            <div class="card">
                <div class="card-header" id="headingOne">
                    <h5 class="mb-0">
                        <button class="btn" type="button" data-toggle="collapse" data-target="#collapseOne" aria-expanded="false" aria-controls="collapseOne" id="writeBt">
                            write
                        </button>
                    </h5>
                </div>
                <div id="collapseOne" class="collapse" aria-labelledby="headingOne" data-parent="#accordionExample">
                    <div class="card-body">
                        <form id="guestBookForm">
                            <div class="form-group">
                                <label>write</label>
                                <input type="text" class="form-control" name="write">
                            </div>
                            <div class="form-group">
                                <label>pw</label>
                                <input type="password" class="form-control" name="pw">
                            </div>
                            <div class="form-group">
                                <label>title</label>
                                <input type="text" class="form-control" name="title">
                            </div>
                            <div class="form-group">
                                <label>contents</label>
                                <textarea class="form-control" name="contents"></textarea>
                            </div>
                        </form>
                        <button class="btn btn-primary" v-on:click="addGuestBook">Submit</button>
                    </div>
                </div>
            </div>
        </div>

        <div id="guestBookListArea">
            <div class="card bg-light mb-3" v-for="(book, index) in guestBook" :key="index">
                <div class="card-header">write</div>
                <div class="card-body">
                    <h5 class="card-title">{{ book.title }}</h5>
                    <p class="card-text">{{ book.contents }}</p>
                </div>
            </div>
        </div>

    </div>
</template>

<script>
    export default {
        name: "GuestBook",
        data () {
            return {
                guestBook: []
            }
        },
        methods: {
            addGuestBook() {
                this.guestBook.push({title: "title", contents: "contents"});
                $("#writeBt").trigger("click");
            }
        }
    }
</script>

<style scoped>
    .accordion{
        margin: 20px 0px 20px 0px;
    }
</style>


